    return total

def tri(n):
    res = []
    for i in range(n + 1):
        if i % 2 == 0:
            res.append(1 + i // 2)
        elif i == 1:
            res.append(3)
        else:
            res.append(res[i - 1] + res[i - 2] + (1 + (i + 1) // 2))
    return res

def valid_date(date):
    if not isinstance(date, str) or not date:
        return False

    parts = date.split("-")
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    month = int(month_str)
    day = int(day_str)

    if month < 1 or month > 12:
        return False

    days_in_month = {
        1: 31, 2: 29, 3: 31, 4: 30,
        5: 31, 6: 30, 7: 31, 8: 31,
        9: 30, 10: 31, 11: 30, 12: 31
    }

    return 1 <= day <= days_in_month[month]

def specialFilter(nums):
