    for num in nums:
        if num > 10:
            s = str(abs(num))
            if s[0] in odd_digits and s[-1] in odd_digits:
                count += 1

    return count

def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] == " ":
            j = i
            while j < len(text) and text[j] == " ":
                j += 1
            count = j - i
            if count > 2:
                result.append("-")
            else:
                result.append("_" * count)
            i = j
        else:
            result.append(text[i])
            i += 1
    return "".join(result)

